#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_SIZE 10
#define MAX_KEY_LEN 100

typedef struct Item {
    char key[MAX_KEY_LEN];
    char* value;
} Item;

typedef struct Map {
    Item* items[MAX_SIZE];
    int size;
} Map;

void initMap(Map* map) {
    map->size = MAX_SIZE;
    for (int i = 0; i < MAX_SIZE; i++) {
        map->items[i] = NULL;
    }
}

void insert(Map* map, const char* key, const char* value) {
    unsigned int index = 0;
    for (int i = 0; key[i]; i++) index += key[i];
    index %= map->size;
    if (map->items[index] != NULL) {
        free(map->items[index]->value);
        map->items[index]->value = strdup(value);
        return;
    }
    Item* item = (Item*)malloc(sizeof(Item));
    strncpy(item->key, key, MAX_KEY_LEN);
    item->value = strdup(value);
    map->items[index] = item;
}

char* get(Map* map, const char* key) {
    unsigned int index = 0;
    for (int i = 0; key[i]; i++) index += key[i];
    index %= map->size;
    if (map->items[index] != NULL && strcmp(map->items[index]->key, key) == 0) {
        return map->items[index]->value;
    }
    return NULL;
}

int removeItem(Map* map, const char* key) {
    unsigned int index = 0;
    for (int i = 0; key[i]; i++) index += key[i];
    index %= map->size;
    if (map->items[index] != NULL && strcmp(map->items[index]->key, key) == 0) {
        free(map->items[index]->value);
        free(map->items[index]);
        map->items[index] = NULL;
        return 1;
    }
    return 0;
}

void printMap(Map* map) {
    printf("{");
    int first = 1;
    for (int i = 0; i < map->size; i++) {
        if (map->items[i] != NULL) {
            if (!first) printf(", ");
            printf("%s: %s", map->items[i]->key, map->items[i]->value);
            first = 0;
        }
    }
    printf("}\n");
}

int main() {
    Map map;
    initMap(&map);
    insert(&map, "name", "Alice");
    insert(&map, "age", "25");
    printf("Map after insert: ");
    printMap(&map);
    printf("Get name: %s\n", get(&map, "name"));
    removeItem(&map, "age");
    printf("Map after remove: ");
    printMap(&map);
    return 0;
}
// Output: Map after insert: {name: Alice, age: 25}
// Output: Get name: Alice
// Output: Map after remove: {name: Alice}

