using System;
using System.Collections.Generic;

class Map {
    private Dictionary<string, object> items;

    public Map() {
        items = new Dictionary<string, object>();
    }

    public void Insert(string key, object value) {
        items[key] = value;
    }

    public object Get(string key) {
        return items.ContainsKey(key) ? items[key] : null;
    }

    public bool Remove(string key) {
        return items.Remove(key);
    }

    public Dictionary<string, object> ToDictionary() {
        return new Dictionary<string, object>(items);
    }
}

class Program {
    static void Main() {
        Map m = new Map();
        m.Insert("name", "Alice");
        m.Insert("age", 25);
        Console.WriteLine("Map after insert: {{ " + string.Join(", ", m.ToDictionary().Select(kv => $"{kv.Key}: {kv.Value}")) + " }}");
        Console.WriteLine("Get name: " + m.Get("name"));
        m.Remove("age");
        Console.WriteLine("Map after remove: {{ " + string.Join(", ", m.ToDictionary().Select(kv => $"{kv.Key}: {kv.Value}")) + " }}");
    }
}
// Output: Map after insert: { name: Alice, age: 25 }
// Output: Get name: Alice
// Output: Map after remove: { name: Alice }

