#include <iostream>
#include <unordered_map>
#include <string>

class Map {
private:
    std::unordered_map<std::string, std::string> items;

public:
    void insert(const std::string& key, const std::string& value) {
        items[key] = value;
    }

    std::string get(const std::string& key) {
        if (items.find(key) != items.end()) {
            return items[key];
        }
        return "";
    }

    bool remove(const std::string& key) {
        if (items.find(key) != items.end()) {
            items.erase(key);
            return true;
        }
        return false;
    }

    void print() {
        std::cout << "{";
        bool first = true;
        for (const auto& item : items) {
            if (!first) std::cout << ", ";
            std::cout << item.first << ": " << item.second;
            first = false;
        }
        std::cout << "}\n";
    }
};

int main() {
    Map m;
    m.insert("name", "Alice");
    m.insert("age", "25");
    std::cout << "Map after insert: ";
    m.print();
    std::cout << "Get name: " << m.get("name") << "\n";
    m.remove("age");
    std::cout << "Map after remove: ";
    m.print();
    return 0;
}
// Output: Map after insert: {name: Alice, age: 25}
// Output: Get name: Alice
// Output: Map after remove: {name: Alice}

